export type Language = 'zh' | 'en';

export interface DrugInfo {
  name: string;
  indications: string;
  dosage: string;
  contraindications: string;
  storage: string;
  sideEffects: string;
  usage_tips: string;
  summary: string;
  isHighRisk: boolean;      // New field: Is this a high-alert medication?
  riskReason: string;       // New field: Why is it high risk?
}

export interface ConditionDetail {
  name: string;             // 疾病名称 / Condition Name
  probability: string;      // 可能性 / Probability
  explanation: string;      // 解释 / Explanation
  medications: string[];    // 药物 / Medications
  treatments: string[];     // 治疗 / Treatments
}

export interface DiagnosisInfo {
  urgency: 'Low' | 'Medium' | 'High'; 
  urgency_reason: string;    
  summary: string;           
  potential_conditions: ConditionDetail[]; 
  lifestyle_advice: string;  
}

export interface Article {
  id: string;
  title: string;
  snippet: string;
  category: string;
  readTime: string;
}

export enum AppMode {
  HOME = 'HOME',
  RESULT = 'RESULT',
  DIAGNOSIS_RESULT = 'DIAGNOSIS_RESULT'
}

export interface LoadingState {
  isLoading: boolean;
  message: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'ai';
  content: string;
  timestamp: number;
}

// Web Speech API Types
export interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  start(): void;
  stop(): void;
  abort(): void;
  onstart: () => void;
  onresult: (event: any) => void;
  onerror: (event: any) => void;
  onend: () => void;
}

declare global {
  interface Window {
    SpeechRecognition: {
      new (): SpeechRecognition;
    };
    webkitSpeechRecognition: {
      new (): SpeechRecognition;
    };
  }
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { DrugInfo, Language } from '../types';
import { t } from '../translations';
import { 
  ArrowLeft, Volume2, StopCircle, AlertTriangle, 
  Pill, FileText, Thermometer, Info, ShieldCheck, HeartPulse, Activity, Copy, Check, Type, Siren, ChevronRight, Home
} from 'lucide-react';
import { FollowUpChat } from './FollowUpChat';

interface ResultCardProps {
  info: DrugInfo;
  onBack: () => void;
  lang: Language;
}

// Optimization: Use React.memo to prevent re-renders when parent state (like Toast) changes
export const ResultCard: React.FC<ResultCardProps> = React.memo(({ info, onBack, lang }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [copied, setCopied] = useState(false);
  // Font scaling state: 0 (100%), 1 (115%), 2 (130%)
  const [fontScale, setFontScale] = useState(0); 
  const T = t[lang];

  useEffect(() => {
    return () => {
      window.speechSynthesis.cancel();
    };
  }, []);

  const handlePlayAudio = () => {
    if (isPlaying) {
      window.speechSynthesis.cancel();
      setIsPlaying(false);
      return;
    }

    const textToRead = info.isHighRisk 
      ? `${T.high_risk_alert}. ${info.riskReason}. ${info.summary}`
      : info.summary;

    const utterance = new SpeechSynthesisUtterance(textToRead);
    utterance.lang = lang === 'zh' ? 'zh-CN' : 'en-US';
    utterance.rate = 1.0;
    utterance.onend = () => setIsPlaying(false);
    utterance.onerror = () => setIsPlaying(false);
    setIsPlaying(true);
    window.speechSynthesis.speak(utterance);
  };

  const handleCopy = () => {
    const text = `
💊 ${info.name} ${info.isHighRisk ? '[⚠️ High Risk]' : ''}
---
📝 ${T.indications}: ${info.indications}
💊 ${T.dosage}: ${info.dosage}
⚠️ ${T.contraindications}: ${info.contraindications}
ℹ️ ${T.side_effects}: ${info.sideEffects}
💡 ${T.tips}: ${info.usage_tips}
    `.trim();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const toggleFontScale = () => {
    setFontScale(prev => (prev + 1) % 3);
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { 
      opacity: 1,
      transition: { staggerChildren: 0.1 }
    }
  };

  const itemVariants = {
    hidden: { y: 20, opacity: 0 },
    visible: { y: 0, opacity: 1 }
  };

  // Construct context for the chat
  const chatContext = JSON.stringify(info);

  // Dynamic style for main content wrapper
  const contentStyle = {
    fontSize: fontScale === 0 ? '100%' : fontScale === 1 ? '115%' : '130%'
  };

  return (
    <div className="w-full h-full flex flex-col relative overflow-hidden bg-slate-50">

      {/* Decorative Side Elements for Large Screens */}
      <div className="hidden xl:block absolute top-1/2 left-10 -translate-y-1/2 opacity-[0.04] pointer-events-none select-none">
         <Pill size={400} className="-rotate-12 text-blue-800" />
      </div>
      <div className="hidden xl:block absolute bottom-0 right-10 opacity-[0.04] pointer-events-none select-none">
         <Activity size={400} className="text-blue-800" />
      </div>

      {/* Sticky Header */}
      <motion.div 
        initial={{ y: -50, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        className="sticky top-0 z-30 bg-white/90 backdrop-blur-md border-b border-slate-200 px-4 py-3 flex items-center justify-between shadow-sm"
      >
        <div className="flex items-center gap-2 overflow-hidden text-sm">
           <button onClick={onBack} className="text-slate-500 hover:text-blue-600 flex items-center gap-1">
             <Home size={14} /> {T.home}
           </button>
           <ChevronRight size={14} className="text-slate-300" />
           <span className="font-bold text-slate-800 truncate max-w-[150px] sm:max-w-[300px]">{info.name}</span>
        </div>

        <div className="flex items-center gap-2">
          {/* Font Size Toggle */}
          <button 
            onClick={toggleFontScale}
            className="p-2 rounded-full hover:bg-slate-100 text-slate-600 transition-all flex items-center justify-center relative"
            title={T.font_size}
          >
             <Type size={20} />
             {fontScale > 0 && (
               <span className="absolute -top-1 -right-1 bg-blue-500 text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center font-bold">
                 {fontScale === 1 ? '+' : '++'}
               </span>
             )}
          </button>

          {/* Copy Button */}
          <button 
            onClick={handleCopy}
            className="p-2 rounded-full hover:bg-blue-50 text-blue-600 transition-all flex items-center gap-1 active:scale-95"
            title={T.copy_report}
          >
             <AnimatePresence mode="wait">
               {copied ? (
                 <motion.div key="check" initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }}>
                    <Check size={20} />
                 </motion.div>
               ) : (
                 <motion.div key="copy" initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }}>
                    <Copy size={20} />
                 </motion.div>
               )}
             </AnimatePresence>
          </button>

           <button 
            onClick={onBack}
            className="ml-2 p-2 rounded-full bg-slate-100 hover:bg-slate-200 text-slate-700 transition-colors shadow-sm active:scale-95 border border-slate-200"
          >
            <ArrowLeft size={20} />
          </button>
        </div>
      </motion.div>

      {/* Main Content Area - Wrapped for Font Scaling */}
      <motion.div 
        className="flex-1 overflow-y-auto p-4 pb-20 no-scrollbar space-y-4 max-w-4xl mx-auto w-full relative z-10"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <div style={contentStyle} className="transition-all duration-300 space-y-4">

          {/* --- HIGH RISK ALERT BANNER --- */}
          {info.isHighRisk && (
            <motion.div 
              variants={itemVariants} 
              className="bg-red-600 rounded-3xl p-5 text-white shadow-xl shadow-red-600/30 flex items-start gap-4 border border-red-500/50 relative overflow-hidden"
            >
              {/* Animated Background Strips */}
              <div className="absolute inset-0 opacity-10 bg-[repeating-linear-gradient(45deg,transparent,transparent_10px,#000_10px,#000_20px)] pointer-events-none"></div>

              <div className="bg-white/20 p-3 rounded-full shrink-0 animate-pulse">
                <Siren size={32} className="text-white" />
              </div>
              <div>
                <h2 className="text-[1.2em] font-bold mb-1 flex items-center gap-2">
                  {T.high_risk_alert}
                </h2>
                <p className="text-white/90 text-[0.95em] font-medium leading-relaxed">
                  {info.riskReason || T.high_risk_desc}
                </p>
              </div>
            </motion.div>
          )}

          {/* 1. Hero Summary Card */}
          <motion.div variants={itemVariants} className="bg-gradient-to-br from-indigo-600 to-blue-500 rounded-3xl p-6 text-white shadow-xl shadow-blue-500/20 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-3 opacity-20">
              <HeartPulse size={120} />
            </div>

            <div className="relative z-10">
              <div className="flex justify-between items-start mb-4">
                <span className="bg-white/20 backdrop-blur-sm px-3 py-1 rounded-full text-[0.75em] font-medium border border-white/10">
                  {T.ai_summary}
                </span>
                <button 
                  onClick={handlePlayAudio}
                  className="flex items-center gap-2 bg-white text-blue-600 px-4 py-2 rounded-full font-bold text-[0.85em] shadow-lg hover:scale-105 transition-transform"
                >
                  {isPlaying ? (
                    <>
                      <StopCircle size={16} /> <span>{T.stop}</span>
                    </>
                  ) : (
                    <>
                      <Volume2 size={16} /> <span>{T.play}</span>
                    </>
                  )}
                </button>
              </div>

              <h1 className="text-[1.75em] font-bold mb-2 leading-tight">{info.name}</h1>
              <p className="text-blue-50 leading-relaxed text-[0.95em] opacity-90">
                {info.summary}
              </p>
            </div>
          </motion.div>

          {/* 2. Main Grid */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">

            {/* Left Column: Info Cards (Takes 2/3 on large screens) */}
            <div className="lg:col-span-2 space-y-4">
              {/* Warning Card */}
              <motion.div variants={itemVariants} className="bg-red-50 rounded-2xl p-5 border border-red-100 flex flex-col gap-2">
                <div className="flex items-center gap-2 text-red-600 font-bold text-[1.1em]">
                  <AlertTriangle size={'1.2em'} />
                  <h3>{T.contraindications}</h3>
                </div>
                <p className="text-slate-700 text-[0.95em] leading-relaxed">
                  {info.contraindications}
                </p>
              </motion.div>

              {/* Usage Tips */}
              <motion.div variants={itemVariants} className="bg-amber-50 rounded-2xl p-5 border border-amber-100 flex flex-col gap-2">
                <div className="flex items-center gap-2 text-amber-600 font-bold text-[1.1em]">
                  <ShieldCheck size={'1.2em'} />
                  <h3>{T.tips}</h3>
                </div>
                <p className="text-slate-700 text-[0.95em] leading-relaxed whitespace-pre-line">
                  {info.usage_tips}
                </p>
              </motion.div>

              {/* Dosage */}
              <motion.div variants={itemVariants} className="bg-white rounded-2xl p-5 border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 text-blue-600 font-bold mb-3 text-[1.1em]">
                  <Pill size={'1.2em'} />
                  <h3>{T.dosage}</h3>
                </div>
                <div className="text-slate-600 text-[0.95em] leading-relaxed bg-slate-50 p-4 rounded-xl border border-slate-100">
                  {info.dosage}
                </div>
              </motion.div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* Indications */}
                  <motion.div variants={itemVariants} className="bg-white rounded-2xl p-5 border border-slate-100 shadow-sm">
                    <div className="flex items-center gap-2 text-indigo-600 font-bold mb-3 text-[1.1em]">
                      <FileText size={'1.2em'} />
                      <h3>{T.indications}</h3>
                    </div>
                    <p className="text-slate-600 text-[0.95em] leading-relaxed">
                      {info.indications}
                    </p>
                  </motion.div>

                  {/* Side Effects */}
                  <motion.div variants={itemVariants} className="bg-white rounded-2xl p-5 border border-slate-100 shadow-sm">
                    <div className="flex items-center gap-2 text-purple-600 font-bold mb-3 text-[1.1em]">
                      <Info size={'1.2em'} />
                      <h3>{T.side_effects}</h3>
                    </div>
                    <p className="text-slate-600 text-[0.95em] leading-relaxed">
                      {info.sideEffects}
                    </p>
                  </motion.div>
              </div>

              {/* Storage */}
              <motion.div variants={itemVariants} className="bg-slate-50 rounded-2xl p-5 border border-slate-200 flex items-center gap-4">
                <div className="bg-white p-3 rounded-full shadow-sm text-slate-500">
                    <Thermometer size={'1.5em'} />
                </div>
                <div>
                  <h4 className="text-[0.8em] font-bold text-slate-400 uppercase tracking-wider">{T.storage}</h4>
                  <p className="text-slate-700 font-medium text-[1em]">{info.storage}</p>
                </div>
              </motion.div>
            </div>

            {/* Right Column: AI Chat Assistant (Takes 1/3 on large screens) */}
            <motion.div variants={itemVariants} className="lg:col-span-1 h-full min-h-[400px]">
              <div className="sticky top-20 h-[calc(100vh-140px)] min-h-[400px]">
                  <FollowUpChat 
                    contextText={chatContext} 
                    lang={lang} 
                    suggestions={[T.suggested_q1_drug, T.suggested_q2_drug]}
                  />
              </div>
            </motion.div>
          </div>

           {/* Source Footer */}
          <div className="text-center text-[10px] text-slate-400 py-6 border-t border-slate-100 mt-8">
            <p>{T.source_attribution}</p>
            <p className="mt-1">{T.disclaimer_text}</p>
          </div>
        </div>
      </motion.div>
    </div>
  );
});

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { DiagnosisInfo, Language } from '../types';
import { t } from '../translations';
import { 
  ArrowLeft, Volume2, StopCircle, Stethoscope, 
  Activity, Thermometer, ShieldAlert, Utensils, HeartPulse, Sparkles, AlertCircle, Dna, Copy, Check, Type, ArrowRight, MousePointerClick, ChevronRight, Pill, Home
} from 'lucide-react';
import { FollowUpChat } from './FollowUpChat';

interface DiagnosisResultCardProps {
  info: DiagnosisInfo;
  onBack: () => void;
  lang: Language;
  onItemClick: (query: string) => void;
}

// Optimization: Use React.memo to prevent re-renders
export const DiagnosisResultCard: React.FC<DiagnosisResultCardProps> = React.memo(({ info, onBack, lang, onItemClick }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [copied, setCopied] = useState(false);
  const [fontScale, setFontScale] = useState(0); 
  const T = t[lang];

  useEffect(() => {
    return () => {
      window.speechSynthesis.cancel();
    };
  }, []);

  const handlePlayAudio = () => {
    if (isPlaying) {
      window.speechSynthesis.cancel();
      setIsPlaying(false);
      return;
    }
    const utterance = new SpeechSynthesisUtterance(info.summary);
    utterance.lang = lang === 'zh' ? 'zh-CN' : 'en-US';
    utterance.rate = 1.0;
    utterance.onend = () => setIsPlaying(false);
    utterance.onerror = () => setIsPlaying(false);
    setIsPlaying(true);
    window.speechSynthesis.speak(utterance);
  };

  const handleCopy = () => {
    const text = `
🩺 ${T.diagnosis_report}
⚠️ ${info.urgency}
---
📝 ${info.summary}
👉 ${info.potential_conditions.map(c => `${c.name} (${c.probability})`).join(', ')}
💊 ${T.rec_meds}: ${info.potential_conditions[0].medications.join(', ')}
🥗 ${T.lifestyle}: ${info.lifestyle_advice}
    `.trim();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const toggleFontScale = () => {
    setFontScale(prev => (prev + 1) % 3);
  };

  // Theme based on urgency
  const getTheme = () => {
    switch (info.urgency) {
      case 'High':
        return {
          bg: 'from-rose-500 to-red-600',
          shadow: 'shadow-red-500/30'
        };
      case 'Medium':
        return {
          bg: 'from-amber-400 to-orange-500',
          shadow: 'shadow-orange-500/30'
        };
      default: // Low
        return {
          bg: 'from-emerald-400 to-teal-500',
          shadow: 'shadow-emerald-500/30'
        };
    }
  };

  const theme = getTheme();
  const selectedCondition = info.potential_conditions[selectedIndex];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { staggerChildren: 0.1 } }
  };

  const itemVariants = {
    hidden: { y: 20, opacity: 0 },
    visible: { y: 0, opacity: 1 }
  };

  const chatContext = JSON.stringify(info);
  const contentStyle = { fontSize: fontScale === 0 ? '100%' : fontScale === 1 ? '115%' : '130%' };

  return (
    <div className="w-full h-full flex flex-col relative overflow-hidden bg-slate-50">

      {/* Decorative Side Elements */}
      <div className="hidden xl:block absolute top-1/2 left-10 -translate-y-1/2 opacity-[0.04] pointer-events-none select-none">
         <Stethoscope size={400} className="text-indigo-800" />
      </div>

      {/* Sticky Header */}
      <motion.div 
        initial={{ y: -50, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        className="sticky top-0 z-30 bg-white/90 backdrop-blur-md border-b border-slate-200 px-4 py-3 flex items-center justify-between shadow-sm"
      >
        <div className="flex items-center gap-2 overflow-hidden text-sm">
          <button onClick={onBack} className="text-slate-500 hover:text-blue-600 flex items-center gap-1">
             <Home size={14} /> {T.home}
           </button>
           <ChevronRight size={14} className="text-slate-300" />
          <span className="font-semibold text-slate-800 flex items-center gap-2">
            <Stethoscope size={18} className="text-blue-500"/>
            {T.diagnosis_report}
          </span>
        </div>

        <div className="flex items-center gap-2">
           <button onClick={toggleFontScale} className="p-2 rounded-full hover:bg-slate-100 text-slate-600 transition-all flex items-center justify-center relative">
             <Type size={20} />
             {fontScale > 0 && (
               <span className="absolute -top-1 -right-1 bg-blue-500 text-white text-[10px] w-4 h-4 rounded-full flex items-center justify-center font-bold">
                 {fontScale === 1 ? '+' : '++'}
               </span>
             )}
          </button>
           <button onClick={handleCopy} className="p-2 rounded-full hover:bg-blue-50 text-blue-600 transition-all flex items-center gap-1 active:scale-95">
             {copied ? <Check size={20} /> : <Copy size={20} />}
          </button>
           <button 
            onClick={onBack}
            className="ml-2 p-2 rounded-full bg-slate-100 hover:bg-slate-200 text-slate-700 transition-colors shadow-sm active:scale-95 border border-slate-200"
          >
            <ArrowLeft size={20} />
          </button>
        </div>
      </motion.div>

      {/* Content */}
      <motion.div 
        className="flex-1 overflow-y-auto p-4 pb-24 no-scrollbar space-y-6 max-w-5xl mx-auto w-full relative z-10"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <div style={contentStyle} className="transition-all duration-300">
         <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

           {/* Left Column (Diagnosis) */}
           <div className="lg:col-span-2 space-y-6">

              {/* Urgency & Summary Card */}
              <motion.div variants={itemVariants} className={`bg-gradient-to-br ${theme.bg} rounded-[2rem] p-6 text-white shadow-xl ${theme.shadow} relative overflow-hidden group`}>
                <div className="absolute -right-10 -top-10 opacity-20 group-hover:rotate-12 transition-transform duration-700">
                  <Activity size={180} />
                </div>

                <div className="relative z-10">
                  <div className="flex justify-between items-start mb-4">
                    <span className="bg-white/20 backdrop-blur-md px-4 py-1.5 rounded-full text-[0.8em] font-bold uppercase tracking-wider border border-white/20 shadow-sm">
                      {info.urgency === 'High' ? T.urgency_high : info.urgency === 'Medium' ? T.urgency_med : T.urgency_low}
                    </span>
                    <button 
                      onClick={handlePlayAudio}
                      className="flex items-center gap-2 bg-white/90 hover:bg-white text-slate-800 px-4 py-1.5 rounded-full font-bold text-[0.8em] shadow-lg transition-all active:scale-95"
                    >
                      {isPlaying ? <StopCircle size={16} /> : <Volume2 size={16} />}
                      <span>{T.play}</span>
                    </button>
                  </div>

                  <h1 className="text-[1.8em] font-bold mb-3 flex items-center gap-3">
                    <Sparkles size={28} className="text-yellow-300"/>
                    {T.preliminary_analysis}
                  </h1>
                  <p className="text-white/95 leading-relaxed text-[1em] font-medium max-w-2xl">
                    {info.summary}
                  </p>
                </div>
              </motion.div>

              {/* --- Interactive Conditions --- */}
              <motion.div variants={itemVariants} className="space-y-4">

                {/* Condition Selector Pills */}
                <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2 px-1">
                  {info.potential_conditions.map((condition, index) => (
                    <button
                      key={index}
                      onClick={() => setSelectedIndex(index)}
                      className={`relative flex-shrink-0 px-6 py-3 rounded-2xl transition-all outline-none border ${
                        selectedIndex === index 
                          ? 'bg-slate-800 text-white border-slate-800 shadow-lg shadow-slate-300 transform scale-[1.02]' 
                          : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'
                      }`}
                    >
                      <div className="flex flex-col items-start gap-1">
                        <span className="font-bold text-[0.95em]">{condition.name}</span>
                        <span className={`text-[0.7em] px-2 py-0.5 rounded-md font-bold uppercase tracking-wide ${
                            selectedIndex === index ? 'bg-white/20 text-white' : 'bg-slate-100 text-slate-400'
                        }`}>
                          {condition.probability}
                        </span>
                      </div>
                    </button>
                  ))}
                </div>

                {/* Main Condition Content */}
                <div className="bg-white rounded-[2rem] p-6 md:p-8 shadow-sm border border-slate-100">
                  <AnimatePresence mode="wait">
                      <motion.div
                        key={selectedIndex}
                        initial={{ opacity: 0, x: 10 }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: -10 }}
                        transition={{ duration: 0.2 }}
                        className="space-y-8"
                      >
                        {/* Pathology Description */}
                        <div>
                           <div className="flex items-center gap-3 mb-3">
                              <div className="p-2 bg-blue-100 rounded-xl text-blue-600">
                                <AlertCircle size={20} />
                              </div>
                              <h4 className="font-bold text-slate-800 text-[1.1em]">{T.pathology}</h4>
                           </div>
                           <p className="text-slate-600 text-[1em] leading-relaxed pl-2 border-l-4 border-blue-100">
                              {selectedCondition.explanation}
                           </p>
                        </div>

                        {/* Action Grid - Medications & Treatments */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

